// Generic class with a bound
class Cache<K, V extends Object> {
  final _store = <K, V>{};
  void put(K k, V v) => _store[k] = v;
  V? get(K k) => _store[k];
}

// Generic method — T is inferred from the argument list
T pickFirst<T>(List<T> xs) {
  if (xs.isEmpty) throw StateError('empty');
  return xs.first;
}

final s = pickFirst<String>(['a', 'b']); // explicit
final n = pickFirst([1, 2, 3]);          // inferred to int

// Bound: constrains T so we can call .compareTo on it
T max<T extends Comparable<T>>(List<T> xs) =>
    xs.reduce((a, b) => a.compareTo(b) >= 0 ? a : b);

final hi = max<int>([3, 1, 9, 2]);  // 9

// Reified — runtime knows the type argument
final xs = <int>[1, 2, 3];
print(xs is List<int>);    // true
print(xs is List<String>); // false

// Extension on a built-in type
extension StringX on String {
  String toSlug() => toLowerCase()
      .replaceAll(RegExp(r'[^a-z0-9]+'), '-')
      .replaceAll(RegExp(r'^-|-\$'), '');
  bool get isBlank => trim().isEmpty;
}

void main() {
  print('Hello, World!'.toSlug()); // hello-world
  print('   '.isBlank);            // true
}

// Generic extension
extension Iter<T> on Iterable<T> {
  T? firstOrNull() => isEmpty ? null : first;
  Map<K, List<T>> groupBy<K>(K Function(T) key) {
    final out = <K, List<T>>{};
    for (final v in this) (out[key(v)] ??= <T>[]).add(v);
    return out;
  }
}

final byLevel = users.groupBy((u) => u.level);

// Named extension — resolves conflicts when two libs add the same name
extension SafeJson on String {
  Map<String, dynamic>? parseJsonOrNull() {
    try { return jsonDecode(this) as Map<String, dynamic>; }
    catch (_) { return null; }
  }
}

