// Standalone mixin
mixin Tappable {
  int _taps = 0;
  int get taps => _taps;
  void tap() => _taps++;
}

// Mixin with a contract — only foldable into ChangeNotifier subclasses
mixin AutoSave on ChangeNotifier {
  Timer? _t;
  @override
  void notifyListeners() {
    super.notifyListeners();
    _t?.cancel();
    _t = Timer(const Duration(seconds: 1), persist);
  }
  void persist();
}

class Settings extends ChangeNotifier with AutoSave {
  int volume = 50;
  void setVolume(int v) { volume = v; notifyListeners(); }
  @override void persist() => prefs.setInt('vol', volume);
}

// Multiple mixins — last one wins on conflict
mixin A { String hi() => 'A'; }
mixin B { String hi() => 'B'; }
class C with A, B {} // C().hi() == 'B'

// Why not inheritance? Service is unrelated to LoggerBase, but still wants logging.
mixin Logger { void log(String s) => print('[$runtimeType] $s'); }
class Auth with Logger {}
class Cache with Logger {}

// sync* — recursive walk over a tree
Iterable<File> walk(Directory dir) sync* {
  for (final entity in dir.listSync()) {
    if (entity is File) yield entity;
    if (entity is Directory) yield* walk(entity); // delegate
  }
}

final first10 = walk(Directory('lib')).take(10);  // lazy — only walks what's needed

// async* — paginated API consumer
Stream<Post> fetchAllPosts(String userId) async* {
  String? cursor;
  do {
    final page = await api.posts(userId, cursor: cursor);
    for (final p in page.items) yield p;
    cursor = page.nextCursor;
  } while (cursor != null);
}

// Consumer
await for (final post in fetchAllPosts('u1').take(20)) {
  print(post.title);
}

// Cleanup with finally — runs on cancellation too
Stream<int> ticks() async* {
  final timer = Stopwatch()..start();
  try {
    for (var i = 0;; i++) {
      await Future.delayed(const Duration(seconds: 1));
      yield i;
    }
  } finally {
    timer.stop();   // ✅ runs when subscription is cancelled
  }
}

enum HttpMethod {
  get('GET', false),
  post('POST', true),
  put('PUT', true),
  delete('DELETE', false);

  final String wire;
  final bool hasBody;
  const HttpMethod(this.wire, this.hasBody);

  bool get isMutation => this != HttpMethod.get;
}

void main() {
  print(HttpMethod.post.wire);      // POST
  print(HttpMethod.get.isMutation); // false
  for (final m in HttpMethod.values) print('${m.name} -> ${m.wire}');
}

