// Switch with patterns — exhaustive over a sealed family
sealed class Shape {}
class Circle extends Shape { final double r; Circle(this.r); }
class Square extends Shape { final double side; Square(this.side); }

double area(Shape s) => switch (s) {
  Circle(:final r) => 3.14 * r * r,
  Square(:final side) => side * side,
};                                    // compile error if a case is missing

// Refutable map pattern — JSON parsing without a library
Object json = {'type': 'user', 'name': 'Ada'};
if (json case {'type': 'user', 'name': String name}) {
  print('user $name');
}

// Discriminated state, exhaustively checked
sealed class AuthState {}
class Anonymous extends AuthState {}
class Authenticating extends AuthState { final String email; Authenticating(this.email); }
class Authenticated extends AuthState { final User user; Authenticated(this.user); }
class AuthFailed extends AuthState { final Object error; AuthFailed(this.error); }

Widget build(AuthState s) => switch (s) {
  Anonymous()                    => const SignInPage(),
  Authenticating(:final email)   => Splash(label: 'Signing in $email…'),
  Authenticated(:final user)     => HomePage(user: user),
  AuthFailed(:final error)       => ErrorPage(error: error),
  // ❌ Drop a case — "switch must be exhaustive on AuthState"
};

// Modifier combos
sealed class Result<T> {}
final class Ok<T> extends Result<T> { final T value; Ok(this.value); }
final class Err<T> extends Result<T> { final Object error; Err(this.error); }
//   final on subtypes -> outside libs cannot subclass them either

// Pattern match + records — Either-style
Result<int> parseInt(String s) =>
    int.tryParse(s) is int v ? Ok(v) : Err('not a number: $s');

final r = parseInt('42');
final label = switch (r) {
  Ok(:final value) => 'got $value',
  Err(:final error) => 'err: $error',
};

// Suppose libfoo.so / foo.dylib exposes:
//   int32_t hash_bytes(const uint8_t* data, int32_t len);
import 'dart:ffi';
import 'dart:io' show Platform;
import 'package:ffi/ffi.dart';

typedef _HashC   = Int32 Function(Pointer<Uint8> data, Int32 len);
typedef _HashDart = int Function(Pointer<Uint8> data, int len);

final _lib = DynamicLibrary.open(
  Platform.isMacOS  ? 'libfoo.dylib'
: Platform.isLinux  ? 'libfoo.so'
: Platform.isWindows? 'foo.dll'
: throw UnsupportedError('platform'));

final _hash = _lib.lookupFunction<_HashC, _HashDart>('hash_bytes');

int hash(List<int> bytes) {
  // Allocate native memory; copy our Dart bytes in
  final buf = calloc<Uint8>(bytes.length);
  try {
    buf.asTypedList(bytes.length).setAll(0, bytes);
    return _hash(buf, bytes.length);
  } finally {
    calloc.free(buf);            // ✅ no GC across the boundary
  }
}

// Usage — no platform channel, no main-thread bottleneck
final h = hash(utf8.encode('hello'));
